import { useEffect, useRef } from "react";
import { useDateTimePicker, formatBasic } from "react-date-range-picker-headless";
import { useFloating, autoUpdate, offset, flip, shift, FloatingPortal } from "@floating-ui/react";
import type { DateTimePickerProps } from "./lib/types";
import { cn, sizeClass } from "./lib/utils";
import { mergeRefs } from "./lib/merge-refs";
import { TimePanelInternal } from "./lib/time-panel-internal";
import { CalendarGrid } from "./calendar-grid";

export function DateTimePicker({
  className,
  style,
  inline,
  hideHeader,
  hideFooter,
  hideWeekdays,
  renderTrigger,
  renderHeader,
  renderWeekdayRow,
  renderDayCell,
  renderFooter,
  renderTimeSection,
  // Form integration
  name,
  ...options
}: DateTimePickerProps) {
  const picker = useDateTimePicker(options);
  const { locale, isOpen, resolvedTimeConfig } = picker;
  const showContent = inline || isOpen;
  const localPopupRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen && !inline && localPopupRef.current) {
      localPopupRef.current.focus({ preventScroll: true });
    }
  }, [isOpen, inline]);

  const { refs, floatingStyles } = useFloating({
    open: !inline && isOpen,
    placement: "bottom-start",
    middleware: [offset(8), flip(), shift({ padding: 8 })],
    whileElementsMounted: autoUpdate,
  });

  const triggerEl =
    !inline &&
    (renderTrigger ? (
      renderTrigger({
        displayValue: picker.displayValue,
        placeholder: locale.dateTimePlaceholder,
        hasValue: picker.hasValue,
        isOpen,
        onToggle: picker.handleToggle,
        onClear: picker.handleClear,
        locale,
        triggerRef: refs.setReference as (node: HTMLElement | null) => void,
      })
    ) : (
      <button
        type="button"
        className="flex items-center justify-between min-w-[200px] px-3.5 py-2 bg-background border border-input rounded-md shadow-sm hover:border-ring/50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:border-ring"
        onClick={picker.handleToggle}
        aria-expanded={isOpen}
        aria-haspopup="dialog"
      >
        <span className={picker.displayValue ? undefined : "text-muted-foreground"}>
          {picker.displayValue || locale.dateTimePlaceholder}
        </span>
        {picker.hasValue && !options.required && (
          <button
            type="button"
            className="ml-2 p-1 -m-1 appearance-none border-0 bg-transparent text-muted-foreground hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring rounded-sm cursor-pointer"
            aria-label={locale.clear}
            onClick={(e) => {
              e.stopPropagation();
              picker.handleClear();
            }}
          >
            ×
          </button>
        )}
      </button>
    ));

  const headerEl =
    !hideHeader &&
    showContent &&
    (renderHeader ? (
      renderHeader({
        month: picker.currentMonth,
        formattedMonthYear: locale.formatMonthYear(picker.currentMonth),
        onPrevMonth: picker.handlePrevMonth,
        onNextMonth: picker.handleNextMonth,
        locale,
        captionLayout: options.captionLayout ?? "buttons",
        years: picker.years,
        months: picker.months,
        onYearSelect: picker.handleYearSelect,
        onMonthSelect: picker.handleMonthSelect,
      })
    ) : options.captionLayout === "dropdown" ? (
      <div className="flex items-center justify-between mb-4">
        <button
          type="button"
          className="flex items-center justify-center w-7 h-7 text-muted-foreground rounded hover:bg-accent hover:text-accent-foreground cursor-pointer"
          onClick={picker.handlePrevMonth}
        >
          {locale.prevMonth}
        </button>
        <div>
          <select
            className="px-1 py-0.5 text-sm bg-transparent border border-transparent rounded hover:border-border focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring cursor-pointer"
            value={picker.currentMonth.getFullYear()}
            onChange={(e) => picker.handleYearSelect(Number(e.target.value))}
            aria-label="Select year"
          >
            {picker.years.map((y) => (
              <option key={y} value={y}>
                {y}
                {locale.yearLabel}
              </option>
            ))}
          </select>{" "}
          <select
            className="px-1 py-0.5 text-sm bg-transparent border border-transparent rounded hover:border-border focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring cursor-pointer"
            value={picker.currentMonth.getMonth()}
            onChange={(e) => picker.handleMonthSelect(Number(e.target.value))}
            aria-label="Select month"
          >
            {picker.months.map((m) => (
              <option key={m} value={m}>
                {locale.months[m]}
                {locale.monthLabel}
              </option>
            ))}
          </select>
        </div>
        <button
          type="button"
          className="flex items-center justify-center w-7 h-7 text-muted-foreground rounded hover:bg-accent hover:text-accent-foreground cursor-pointer"
          onClick={picker.handleNextMonth}
        >
          {locale.nextMonth}
        </button>
      </div>
    ) : (
      <div className="flex items-center justify-between mb-4">
        <button
          type="button"
          className="flex items-center justify-center w-7 h-7 text-muted-foreground rounded hover:bg-accent hover:text-accent-foreground cursor-pointer"
          onClick={picker.handlePrevMonth}
        >
          {locale.prevMonth}
        </button>
        <span className="font-semibold text-[15px]">
          {locale.formatMonthYear(picker.currentMonth)}
        </span>
        <button
          type="button"
          className="flex items-center justify-center w-7 h-7 text-muted-foreground rounded hover:bg-accent hover:text-accent-foreground cursor-pointer"
          onClick={picker.handleNextMonth}
        >
          {locale.nextMonth}
        </button>
      </div>
    ));

  const timeSectionEl =
    showContent &&
    (renderTimeSection ? (
      renderTimeSection({
        displayValue: picker.timeDisplayValue,
        label: "",
        timeConfig: resolvedTimeConfig,
        hour: picker.tempHour,
        minute: picker.tempMinute,
        second: picker.tempSecond,
        period: picker.tempPeriod,
      })
    ) : (
      <div className="mt-4 pt-4 border-t border-border">
        <span className="text-xs font-medium text-muted-foreground">{locale.hourLabel || ""}</span>
        <TimePanelInternal
          hour={picker.tempHour}
          minute={picker.tempMinute}
          second={picker.tempSecond}
          period={picker.tempPeriod}
          onHourChange={picker.handleHourChange}
          onMinuteChange={picker.handleMinuteChange}
          onSecondChange={picker.handleSecondChange}
          onPeriodChange={picker.handlePeriodChange}
          timeConfig={resolvedTimeConfig}
        />
      </div>
    ));

  const footerEl =
    !hideFooter &&
    showContent &&
    (renderFooter ? (
      renderFooter({
        canConfirm: picker.canConfirm,
        hasValue: picker.hasValue,
        onConfirm: picker.handleConfirm,
        onCancel: picker.handleCancel,
        onClear: picker.handleClear,
        locale,
      })
    ) : (
      <div className="flex justify-end gap-2 mt-4 pt-4 border-t border-border">
        {picker.hasValue && (
          <button
            type="button"
            className="px-3 py-1.5 text-sm text-muted-foreground hover:text-foreground hover:bg-accent rounded-md transition-colors cursor-pointer"
            onClick={picker.handleClear}
          >
            {locale.clear}
          </button>
        )}
        <button
          type="button"
          className="px-3 py-1.5 text-sm text-muted-foreground hover:text-foreground hover:bg-accent rounded-md transition-colors cursor-pointer"
          onClick={picker.handleCancel}
        >
          {locale.cancel}
        </button>
        <button
          type="button"
          className="px-3 py-1.5 text-sm text-primary-foreground bg-primary hover:bg-primary/90 rounded-md transition-colors disabled:opacity-50 disabled:pointer-events-none cursor-pointer"
          onClick={picker.handleConfirm}
          disabled={!picker.canConfirm}
        >
          {locale.confirm}
        </button>
      </div>
    ));

  const calendarContent = (
    <>
      {headerEl}
      {picker.calendars.map((cal) => (
        <CalendarGrid
          key={formatBasic(cal.month, "YYYY-MM")}
          calendar={cal}
          locale={locale}
          focusedDate={picker.focusedDate}
          getDayProps={picker.getDayProps}
          onDateClick={picker.handleDateClick}
          showTitle={(options.numberOfMonths ?? 1) > 1}
          hideWeekdays={hideWeekdays}
          captionLayout={options.captionLayout}
          years={picker.years}
          monthOptions={picker.months}
          onYearSelect={picker.handleYearSelect}
          onMonthSelect={picker.handleMonthSelect}
          renderWeekdayRow={renderWeekdayRow}
          renderDayCell={renderDayCell}
        />
      ))}
      {timeSectionEl}
      {footerEl}
    </>
  );

  return (
    <div
      ref={mergeRefs(picker.containerRef, refs.setReference)}
      className={cn(
        "relative w-max font-sans text-[13px] text-foreground select-none",
        sizeClass(options.size),
        className,
      )}
      style={style}
    >
      {name && (
        <input
          type="hidden"
          name={name}
          value={options.value ? formatBasic(options.value, "YYYY-MM-DD HH:mm:ss") : ""}
        />
      )}
      {triggerEl}

      {showContent && !inline && (
        <FloatingPortal>
          <div
            ref={mergeRefs(refs.setFloating, picker.popupRef, localPopupRef)}
            style={floatingStyles}
            className="z-50 p-4 bg-popover border border-border rounded-lg shadow-md"
            onKeyDown={picker.handleKeyDown}
            tabIndex={0}
            role="dialog"
            aria-modal="true"
            aria-label={locale.dateTimePlaceholder}
            aria-activedescendant={
              picker.focusedDate ? `rdrp-day-${locale.formatDate(picker.focusedDate)}` : undefined
            }
          >
            {calendarContent}
          </div>
        </FloatingPortal>
      )}

      {showContent && inline && (
        <div
          className="p-4 bg-popover border border-border rounded-lg"
          onKeyDown={picker.handleKeyDown}
          tabIndex={0}
          role="group"
          aria-label="Date and time picker"
          aria-activedescendant={
            picker.focusedDate ? `rdrp-day-${locale.formatDate(picker.focusedDate)}` : undefined
          }
        >
          {calendarContent}
        </div>
      )}
    </div>
  );
}

import type { RefObject } from "react";
import { useTimePicker, padNumber, to12Hour } from "react-date-range-picker-headless";
import type { TimePanelInternalProps } from "./types";
import { cn } from "./utils";

export function TimePanelInternal({
  hour,
  minute,
  second,
  period,
  onHourChange,
  onMinuteChange,
  onSecondChange,
  onPeriodChange,
  timeConfig,
}: TimePanelInternalProps) {
  const displayHour = timeConfig.hourFormat === "12" ? to12Hour(hour).hour : hour;

  const tp = useTimePicker({
    hour: displayHour,
    minute,
    second,
    period,
    onHourChange,
    onMinuteChange,
    onSecondChange,
    onPeriodChange,
    precision: timeConfig.precision,
    hourFormat: timeConfig.hourFormat,
    minuteStep: timeConfig.minuteStep,
    secondStep: timeConfig.secondStep,
    itemHeight: timeConfig.itemHeight,
  });

  const handleKeyDown = (
    e: React.KeyboardEvent,
    items: number[],
    selectedValue: number,
    onItemClick: (v: number) => void,
  ) => {
    const currentIndex = items.indexOf(selectedValue);
    if (currentIndex < 0) return;

    if (e.key === "ArrowUp") {
      e.preventDefault();
      const next = currentIndex > 0 ? currentIndex - 1 : items.length - 1;
      onItemClick(items[next]);
    } else if (e.key === "ArrowDown") {
      e.preventDefault();
      const next = currentIndex < items.length - 1 ? currentIndex + 1 : 0;
      onItemClick(items[next]);
    } else if (e.key === "Home") {
      e.preventDefault();
      onItemClick(items[0]);
    } else if (e.key === "End") {
      e.preventDefault();
      onItemClick(items[items.length - 1]);
    } else if (e.key === "Enter" || e.key === " ") {
      e.preventDefault();
    }
  };

  const renderColumn = (
    ref: RefObject<HTMLDivElement | null>,
    items: number[],
    selectedValue: number,
    onItemClick: (v: number) => void,
    onScroll: () => void,
    slug: string,
    ariaLabel?: string,
  ) => (
    <div
      ref={ref}
      className="flex-1 h-[160px] overflow-y-auto [scrollbar-width:none] [scroll-snap-type:y_mandatory] [&::-webkit-scrollbar]:hidden"
      onScroll={onScroll}
      role="listbox"
      aria-label={ariaLabel}
      tabIndex={0}
      aria-activedescendant={`time-${slug}-${selectedValue}`}
      onKeyDown={(e) => handleKeyDown(e, items, selectedValue, onItemClick)}
    >
      {Array.from({ length: tp.centerIndex }).map((_, i) => (
        <div key={`pt-${i}`} className="h-8 shrink-0" />
      ))}
      {items.map((item) => (
        <div
          id={`time-${slug}-${item}`}
          key={item}
          role="option"
          aria-selected={item === selectedValue}
          aria-label={ariaLabel ? `${padNumber(item)} ${ariaLabel.toLowerCase()}` : undefined}
          data-slot="time-item"
          className={cn(
            "h-8 flex items-center justify-center cursor-pointer text-sm text-muted-foreground [scroll-snap-align:center] transition-colors select-none hover:text-foreground",
            item === selectedValue && "text-foreground font-semibold",
          )}
          onClick={() => onItemClick(item)}
        >
          {padNumber(item)}
        </div>
      ))}
      {Array.from({ length: tp.centerIndex }).map((_, i) => (
        <div key={`pb-${i}`} className="h-8 shrink-0" />
      ))}
    </div>
  );

  return (
    <div
      className="relative inline-flex items-center justify-center min-w-[120px] h-[176px]"
      data-slot="time-panel"
    >
      <div className="absolute left-1 right-1 h-8 rounded-md bg-primary/8 pointer-events-none" />
      <div className="relative flex items-center w-full h-full">
        {renderColumn(
          tp.hourListRef,
          tp.hours,
          displayHour,
          tp.handleHourClick,
          tp.handleHourScroll,
          "hour",
          "Hours",
        )}

        {tp.showMinutes && (
          <>
            <div className="text-sm font-semibold text-foreground w-3 text-center shrink-0">:</div>
            {renderColumn(
              tp.minuteListRef,
              tp.minutes,
              minute,
              tp.handleMinuteClick,
              tp.handleMinuteScroll,
              "minute",
              "Minutes",
            )}
          </>
        )}

        {tp.showSeconds && (
          <>
            <div className="text-sm font-semibold text-foreground w-3 text-center shrink-0">:</div>
            {renderColumn(
              tp.secondListRef,
              tp.seconds,
              second,
              tp.handleSecondClick,
              tp.handleSecondScroll,
              "second",
              "Seconds",
            )}
          </>
        )}

        {tp.is12Hour && (
          <button
            type="button"
            className="h-8 flex items-center justify-center cursor-pointer text-sm text-foreground font-semibold hover:bg-accent hover:text-accent-foreground rounded-md"
            onClick={tp.handlePeriodToggle}
            aria-label={`Toggle AM/PM, current: ${period}`}
            aria-pressed={period === "PM"}
          >
            {period}
          </button>
        )}
      </div>
    </div>
  );
}
